={{ {
  "model": "llama-3.1-8b-instant",
  "temperature": 0.6,
  "response_format": { "type": "json_object" },
  "messages": [
    {
      "role": "system",
      "content": "You are an elite, first-principles business engineer. Your job is to translate a VALIDATED business opportunity into a concrete, execution-ready acquisition system. Output ONLY valid JSON."
    },
    {
      "role": "user",
      "content": "Build a high-velocity acquisition funnel for the following validated offer.

INPUT DATA:
Offer: " + $json.body.selected_offer.offer + "
ICP: " + $json.body.selected_offer.ICP + "
Promise: " + $json.body.selected_offer.promise + "
Pricing: " + $json.body.selected_offer.pricing + "
Guarantee: " + $json.body.selected_offer.guarantee + "
Validation Score: " + $json.body.validation_context.score + "
Validation Reason: " + $json.body.validation_context.reason + "

STRICT OUTPUT FORMAT (JSON ONLY):
{
  "funnel": {
    "hook": "Short angle",
    "landing_page": { "headline": "", "subheadline": "", "cta": "" },
    "lead_magnet": "",
    "acquisition_channels": [""],
    "conversion_flow": [""],
    "first_7_day_execution": ["" ]
  }
}"
    }
  ]
} }}

assignments.value:
={{ 
(() => {
  const content = $json.choices?.[0]?.message?.content;
  if (!content) return { error: 'No response from AI' };

  try {
    const cleaned = content.replace(/```json|```/g, '').trim();
    const match = cleaned.match(/\{[\s\S]*\}/);
    return match ? JSON.parse(match[0]) : { error: 'Invalid JSON format' };
  } catch (e) {
    return { error: 'Parsing error: ' + e.message };
  }
})()
}}
